type Nullable<T> = T | null | undefined;

type ScheduleItem = { time?: string; label?: string; detail?: string };
type FaqItem = { q?: string; a?: string };

const mosaicResizeControllers = new WeakMap<HTMLElement, AbortController>();
const mosaicLastViewport = new WeakMap<HTMLElement, { w: number; h: number }>();

type BackgroundMosaicConfig = {
  /** @deprecated use tileMinMobile / tileMinDesktop */
  tileMin?: number;
  tileMinMobile?: number;
  tileMinDesktop?: number;
  tileMax?: number;
  gap?: number;
  parallax?: number;
  videoChance?: number;
};

type BackgroundConfig = {
  mode?: "slideshow" | "mosaic";
  images?: string[];
  media?: string[];
  intervalMs?: number;
  overlayStrength?: number;
  vignetteStrength?: number;
  filmGrain?: boolean;
  mosaic?: BackgroundMosaicConfig;
};

type ThemeConfig = { accent?: string; accent2?: string };

type MusicConfig = {
  enabled?: boolean;
  src?: string;
  startAtSeconds?: number;
  volume?: number;
  loop?: boolean;
  startLabel?: string;
  hint?: string;
};

type SectionsConfig = {
  about?: { enabled?: boolean; title?: string; text?: string };
  important?: { enabled?: boolean; title?: string; bullets?: string[] };
  rules?: { enabled?: boolean; title?: string; bullets?: string[] };
  schedule?: { enabled?: boolean; title?: string; items?: ScheduleItem[] };
  whatToBring?: { enabled?: boolean; title?: string; bullets?: string[] };
  gallery?: { enabled?: boolean; title?: string; images?: string[] };
  faq?: { enabled?: boolean; title?: string; items?: FaqItem[] };
};

type EventConfig = {
  title?: string;
  subtitle?: string;
  dateText?: string;
  timeText?: string;
  locationName?: string;
  locationAddress?: string;
  locationImages?: string[];
  mapsUrl?: string;
  rsvp?: {
    enabled?: boolean;
    ctaText?: string;
    whatsappPhoneE164?: string;
    whatsappPrefill?: string;
  };
};

type AppConfig = {
  event?: EventConfig;
  sections?: SectionsConfig;
  background?: BackgroundConfig;
  theme?: ThemeConfig;
  music?: MusicConfig;
};

async function loadConfig(): Promise<AppConfig> {
  const res = await fetch(`./config.json?v=${Date.now()}`, { cache: "no-store" });
  if (!res.ok) throw new Error(`Falha ao carregar config.json (${res.status})`);
  return (await res.json()) as AppConfig;
}

function qs<T extends Element = Element>(sel: string, root: ParentNode = document): T | null {
  return root.querySelector(sel) as T | null;
}

function setText(id: string, value: Nullable<string>) {
  const el = qs<HTMLElement>(`[data-bind="${id}"]`);
  if (!el) return;
  el.textContent = value ?? "";
}

function setTextAll(id: string, value: Nullable<string>) {
  const els = document.querySelectorAll<HTMLElement>(`[data-bind="${id}"]`);
  for (const el of els) el.textContent = value ?? "";
}

function setHref(id: string, value: Nullable<string>) {
  const el = qs<HTMLAnchorElement>(`[data-href="${id}"]`);
  if (!el) return;
  if (!value) {
    el.setAttribute("aria-disabled", "true");
    el.removeAttribute("href");
    return;
  }
  el.setAttribute("href", value);
}

function setEnabled(sectionId: string, enabled: boolean) {
  const el = qs<HTMLElement>(`[data-section="${sectionId}"]`);
  if (!el) return;
  el.hidden = !enabled;
}

function renderBullets(targetSel: string, bullets: string[] = []) {
  const ul = qs<HTMLUListElement>(targetSel);
  if (!ul) return;
  ul.innerHTML = "";
  for (const b of bullets) {
    const li = document.createElement("li");
    li.textContent = b;
    ul.appendChild(li);
  }
}

function renderSchedule(items: ScheduleItem[] = []) {
  const root = qs<HTMLElement>("[data-schedule]");
  if (!root) return;
  root.innerHTML = "";
  for (const it of items) {
    const div = document.createElement("div");
    div.className = "titem";
    div.innerHTML = `
      <div class="titem__time">${escapeHtml(it.time ?? "")}</div>
      <div>
        <div class="titem__label">${escapeHtml(it.label ?? "")}</div>
        <div class="titem__detail">${escapeHtml(it.detail ?? "")}</div>
      </div>
    `;
    root.appendChild(div);
  }
}

function renderGallery(images: string[] = []) {
  const root = qs<HTMLElement>("[data-gallery]");
  if (!root) return;
  root.innerHTML = "";
  for (const src of images) {
    const a = document.createElement("a");
    a.className = "gimg";
    a.href = src;
    a.target = "_blank";
    a.rel = "noreferrer";
    a.innerHTML = `<img alt="Foto da festa" loading="lazy" src="${escapeAttr(src)}" />`;
    const img = a.querySelector("img");
    if (img) setImageFallback(img, "assets/partyImages/1.jpeg");
    root.appendChild(a);
  }
}

function renderLocationGallery(images: string[] = []) {
  const card = qs<HTMLElement>("[data-location-card]");
  const root = qs<HTMLElement>("[data-location-gallery]");
  if (!card || !root) return;

  const list = Array.isArray(images) ? images.filter(Boolean) : [];
  if (!list.length) {
    card.hidden = true;
    root.innerHTML = "";
    return;
  }

  card.hidden = false;
  root.innerHTML = "";
  for (const src of list) {
    const a = document.createElement("a");
    a.className = "locallery__img";
    a.href = src;
    a.target = "_blank";
    a.rel = "noreferrer";
    a.innerHTML = `<img alt="Foto do local" loading="lazy" src="${escapeAttr(src)}" />`;
    const img = a.querySelector("img");
    if (img) setImageFallback(img, "assets/local/1.jpeg");
    root.appendChild(a);
  }
}

function renderFaq(items: FaqItem[] = []) {
  const root = qs<HTMLElement>("[data-faq]");
  if (!root) return;
  root.innerHTML = "";
  for (const it of items) {
    const d = document.createElement("details");
    d.className = "qa";
    const q = escapeHtml(it.q ?? "");
    const a = escapeHtml(it.a ?? "");
    d.innerHTML = `<summary>${q}</summary><p>${a}</p>`;
    root.appendChild(d);
  }
}

function escapeHtml(s: unknown) {
  return String(s)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function escapeAttr(s: unknown) {
  return String(s).replace(/"/g, "&quot;");
}

function setImageFallback(img: HTMLImageElement, fallbackSrc: string) {
  const fb = String(fallbackSrc ?? "").trim();
  if (!fb) return;
  img.addEventListener(
    "error",
    () => {
      // Evita loop se o fallback também falhar
      if ((img as any).dataset?.fallbackApplied === "1") return;
      (img as any).dataset.fallbackApplied = "1";
      img.src = fb;
    },
    { once: true }
  );
}

function setVisualVhCssVar() {
  const vh = window.visualViewport?.height ?? window.innerHeight;
  const vvh = Math.max(1, vh) / 100;
  document.documentElement.style.setProperty("--vvh", `${vvh}px`);

  const vw = window.visualViewport?.width ?? window.innerWidth;
  const vvw = Math.max(1, vw) / 100;
  document.documentElement.style.setProperty("--vvw", `${vvw}px`);
}

function setTheme(theme: Nullable<ThemeConfig>) {
  if (!theme) return;
  const r = document.documentElement;
  if (theme.accent) r.style.setProperty("--accent", theme.accent);
  if (theme.accent2) r.style.setProperty("--accent2", theme.accent2);
}

function setupBackground(bg: Nullable<BackgroundConfig>) {
  const layerA = qs<HTMLElement>("[data-bg-layer='a']");
  const layerB = qs<HTMLElement>("[data-bg-layer='b']");
  const mosaicRoot = qs<HTMLElement>("[data-bg-mosaic]");
  const mosaicClone = qs<HTMLElement>("[data-bg-mosaic-clone]");
  const mosaicTrack = qs<HTMLElement>("[data-bg-mosaic-track]");
  const overlay = qs<HTMLElement>("[data-bg-overlay]");
  const vignette = qs<HTMLElement>("[data-bg-vignette]");
  const grain = qs<HTMLElement>("[data-grain]");
  if (!layerA || !layerB || !overlay || !vignette) return;

  const overlayStrength = clamp01(bg?.overlayStrength ?? 0.62);
  const vignetteStrength = clamp01(bg?.vignetteStrength ?? 0.55);
  overlay.style.opacity = String(overlayStrength);
  vignette.style.opacity = String(vignetteStrength);
  if (grain) grain.style.display = bg?.filmGrain ? "block" : "none";

  const mode = bg?.mode ?? "slideshow";

  if (mode === "mosaic" && mosaicRoot) {
    const media = Array.isArray(bg?.media) ? bg!.media!.filter(Boolean) : [];
    if (!media.length) {
      layerA.style.backgroundImage =
        "linear-gradient(135deg, rgba(var(--c-accent) / 0.22), rgba(var(--c-contrast) / 0.18))";
      layerA.classList.add("is-on");
      layerB.classList.remove("is-on");
      mosaicRoot.innerHTML = "";
      mosaicRoot.style.display = "none";
      if (mosaicClone) mosaicClone.innerHTML = "";
      return;
    }

    layerA.classList.remove("is-on");
    layerB.classList.remove("is-on");
    mosaicRoot.style.display = "grid";
    renderMosaic(mosaicRoot, media, bg?.mosaic);
    if (mosaicClone) {
      mosaicClone.style.display = "grid";
      mosaicClone.innerHTML = mosaicRoot.innerHTML;
      const tile = mosaicRoot.style.getPropertyValue("--tile");
      const gap = mosaicRoot.style.getPropertyValue("--gap");
      if (tile) mosaicClone.style.setProperty("--tile", tile);
      if (gap) mosaicClone.style.setProperty("--gap", gap);
    }
    // Depois de atualizar DOM, "rearmar" a animação do track ajuda o browser
    // a não pausar/ficar fora de sincronia em mobile (vh mudando durante load).
    if (mosaicTrack) {
      mosaicTrack.style.animation = "none";
      mosaicTrack.getBoundingClientRect(); // force reflow
      mosaicTrack.style.animation = "";
    }
    return;
  }

  const images = Array.isArray(bg?.images) ? bg!.images!.filter(Boolean) : [];
  if (!images.length) {
    layerA.style.backgroundImage =
      "linear-gradient(135deg, rgba(var(--c-accent) / 0.22), rgba(var(--c-contrast) / 0.18))";
    layerA.classList.add("is-on");
    layerB.classList.remove("is-on");
    if (mosaicRoot) {
      mosaicRoot.innerHTML = "";
      mosaicRoot.style.display = "none";
    }
    return;
  }

  const intervalMs = Math.max(2500, Number(bg?.intervalMs ?? 6500));
  let idx = 0;
  let onA = true;

  const setLayer = (layer: HTMLElement, src: string) => {
    layer.style.backgroundImage = `url("${src}")`;
  };

  setLayer(layerA, images[idx % images.length]!);
  layerA.classList.add("is-on");
  layerB.classList.remove("is-on");
  if (mosaicRoot) {
    mosaicRoot.innerHTML = "";
    mosaicRoot.style.display = "none";
    if (mosaicClone) mosaicClone.innerHTML = "";
  }

  if (mode !== "slideshow" || images.length === 1) return;

  window.setInterval(() => {
    idx = (idx + 1) % images.length;
    const nextSrc = images[idx]!;
    if (onA) {
      setLayer(layerB, nextSrc);
      layerB.classList.add("is-on");
      layerA.classList.remove("is-on");
    } else {
      setLayer(layerA, nextSrc);
      layerA.classList.add("is-on");
      layerB.classList.remove("is-on");
    }
    onA = !onA;
  }, intervalMs);
}

function renderMosaic(root: HTMLElement, media: string[], mosaicCfg: Nullable<BackgroundMosaicConfig>) {
  const isMobile = window.matchMedia("(max-width: 560px)").matches;
  const tileMinRaw = isMobile
    ? Number(mosaicCfg?.tileMinMobile ?? mosaicCfg?.tileMin ?? 50)
    : Number(mosaicCfg?.tileMinDesktop ?? mosaicCfg?.tileMin ?? 120);
  const tileMin = Math.max(16, tileMinRaw);
  const tileMax = Math.max(tileMin, Number(mosaicCfg?.tileMax ?? 220));
  const gap = Math.max(0, Number(mosaicCfg?.gap ?? 6));

  const pickTile = () => {
    // No mobile, mantém estável pra evitar "pulos" enquanto o viewport muda durante o loading.
    const size = isMobile ? Math.round(tileMin) : Math.round(tileMin + (tileMax - tileMin) * Math.random());
    root.style.setProperty("--tile", `${size}px`);
    root.style.setProperty("--gap", `${gap}px`);
  };
  pickTile();

  root.innerHTML = "";

  const isVideo = (src: string) => /\.(mp4|webm|mov)$/i.test(src);
  const isImage = (src: string) => /\.(png|jpe?g|webp|avif|gif)$/i.test(src);
  const isJpegOnly = (src: string) => /\.jpeg$/i.test(src);

  const vh = window.visualViewport?.height ?? window.innerHeight;
  const vw = window.visualViewport?.width ?? window.innerWidth;

  // Garante cobertura total da tela: calcula quantas tiles cabem (cols x rows)
  // e gera uma folga para compensar tiles "tall" e gaps.
  const tile = Math.max(16, Math.round(Number(root.style.getPropertyValue("--tile").replace("px", "")) || tileMin));
  const step = Math.max(1, tile + gap);
  const cols = Math.max(2, Math.floor((vw + gap) / step));
  const rows = Math.max(2, Math.ceil((vh + gap) / step));
  const base = cols * rows;

  const slack = isMobile ? 1.55 : 1.8;
  const minTiles = Math.max(base, isMobile ? 14 : 26);
  const maxTiles = isMobile ? Math.max(40, base * 3) : Math.max(120, base * 4);
  // Mesmo com cálculo de densidade, aqui vamos permitir renderizar tudo
  // (o mosaico pode ficar mais pesado se houver muitas imagens).
  let count = clampInt(Math.round(base * slack), minTiles, maxTiles);

  const shuffle = (arr: string[]) => {
    for (let i = arr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [arr[i], arr[j]] = [arr[j], arr[i]];
    }
    return arr;
  };

  // Mostrar tudo ao mesmo tempo (sem subset aleatório).
  // No mobile, continua removendo vídeos por padrão (só fotos).
  const baseMedia = isMobile ? media.filter((s) => !isVideo(s)) : media;
  const chosen = shuffle([...baseMedia]);
  // Mostra todas pelo menos 1x e completa a grade repetindo se precisar.
  count = Math.max(chosen.length, minTiles);

  for (let i = 0; i < count; i++) {
    const src = chosen[i % chosen.length]!;
    const tile = document.createElement("div");
    tile.className = "bg__tile";

    // regra: tudo que NÃO for .jpeg vira "storie"
    if (!isJpegOnly(src)) tile.classList.add("bg__tile--tall");

    if (isVideo(src)) {
      const v = document.createElement("video");
      v.src = src;
      forceMutedInline(v);
      v.loop = true;
      v.autoplay = true;
      v.preload = "metadata";
      tile.appendChild(v);
      v.play().catch(() => {});
    } else if (isImage(src)) {
      const img = document.createElement("img");
      img.src = src;
      img.alt = "";
      img.loading = "lazy";
      tile.appendChild(img);
    } else {
      const img = document.createElement("img");
      img.src = src;
      img.alt = "";
      img.loading = "lazy";
      tile.appendChild(img);
    }

    root.appendChild(tile);
  }

  // Garante apenas 1 listener por root (evita re-render em cascata).
  mosaicResizeControllers.get(root)?.abort();
  const controller = new AbortController();
  mosaicResizeControllers.set(root, controller);

  let t = 0;
  const onResize = () => {
    const w = window.innerWidth;
    const h = window.visualViewport?.height ?? window.innerHeight;
    const last = mosaicLastViewport.get(root);
    mosaicLastViewport.set(root, { w, h });

    // No mobile, ignora "micro resizes" comuns durante o loading (barra do navegador).
    if (isMobile && last) {
      const dw = Math.abs(w - last.w);
      const dh = Math.abs(h - last.h);
      if (dw < 2 && dh < 120) return;
    }

    window.clearTimeout(t);
    t = window.setTimeout(() => renderMosaic(root, media, mosaicCfg), 220);
  };
  window.addEventListener("resize", onResize, { passive: true, signal: controller.signal });
}

function setupActiveNav() {
  const chips = Array.from(document.querySelectorAll<HTMLAnchorElement>(".chip[data-nav]"));
  if (!chips.length) return;

  const byId = new Map<string, HTMLAnchorElement>();
  for (const chip of chips) {
    const id = chip.getAttribute("data-nav");
    if (id) byId.set(id, chip);
  }

  const sectionIds = Array.from(byId.keys());
  const sections = sectionIds
    .map((id) => document.getElementById(id))
    .filter((el): el is HTMLElement => !!el);

  if (!sections.length) return;

  const setActive = (id: string) => {
    for (const [k, chip] of byId) chip.classList.toggle("is-active", k === id);
  };

  setActive(sections[0]?.id ?? "info");

  const io = new IntersectionObserver(
    (entries) => {
      const visible = entries
        .filter((e) => e.isIntersecting)
        .sort((a, b) => (b.intersectionRatio ?? 0) - (a.intersectionRatio ?? 0));
      const top = visible[0]?.target as HTMLElement | undefined;
      if (top?.id) setActive(top.id);
    },
    {
      root: null,
      rootMargin: "-90px 0px -55% 0px",
      threshold: [0.12, 0.25, 0.35, 0.5, 0.7],
    },
  );

  for (const el of sections) io.observe(el);
}

function setupStickyCta() {
  const sticky = qs<HTMLElement>("[data-sticky-cta]");
  if (!sticky) return null;

  const footer = qs<HTMLElement>(".footer");
  const onMobile = () => window.matchMedia("(max-width: 560px)").matches;

  let rsvpAvailable = false;
  let footerInView = false;

  const update = () => {
    const y = window.scrollY || document.documentElement.scrollTop || 0;
    const shouldShow = onMobile() && rsvpAvailable && !footerInView && y > 240;
    sticky.hidden = !shouldShow;
  };

  if (footer) {
    const io = new IntersectionObserver(
      (entries) => {
        footerInView = !!entries[0]?.isIntersecting;
        update();
      },
      { root: null, threshold: 0.01 },
    );
    io.observe(footer);
  }

  window.addEventListener("scroll", () => requestAnimationFrame(update), { passive: true });
  window.addEventListener("resize", () => requestAnimationFrame(update), { passive: true });

  update();

  return {
    setAvailable: (available: boolean) => {
      rsvpAvailable = available;
      update();
    },
  };
}

function clampInt(n: unknown, min: number, max: number) {
  const x = Math.round(Number(n));
  if (!Number.isFinite(x)) return min;
  return Math.min(max, Math.max(min, x));
}

function clamp01(x: unknown) {
  const n = Number(x);
  if (!Number.isFinite(n)) return 0;
  return Math.min(1, Math.max(0, n));
}

function forceMutedInline(v: HTMLVideoElement) {
  // iOS/Safari: além de `muted`, garanta `defaultMuted` + atributo.
  // `volume=0` evita casos raros de áudio “vazar”.
  v.muted = true;
  v.defaultMuted = true;
  v.volume = 0;
  v.playsInline = true;
  v.setAttribute("muted", "");
  v.setAttribute("playsinline", "");
  v.setAttribute("webkit-playsinline", "");
}

function buildWhatsappLink(phoneE164: Nullable<string>, prefill: Nullable<string>) {
  const phone = String(phoneE164 ?? "").replace(/[^\d+]/g, "");
  const text = String(prefill ?? "");
  if (!phone) return "";
  const encoded = encodeURIComponent(text).replace(/%250A/g, "%0A");
  const digits = phone.replace(/\+/g, "");
  return `https://wa.me/${digits}?text=${encoded}`;
}

function applyConfig(cfg: AppConfig) {
  const ev = cfg?.event ?? {};
  const sections = cfg?.sections ?? {};

  setTheme(cfg?.theme);
  setupBackground(cfg?.background);

  setTextAll("event.title", ev.title);
  setTextAll("event.subtitle", ev.subtitle);
  setTextAll("event.dateText", ev.dateText);
  setTextAll("event.timeText", ev.timeText);
  setTextAll("event.locationName", ev.locationName);
  setTextAll("event.locationAddress", ev.locationAddress);

  setHref("event.mapsUrl", ev.mapsUrl);
  renderLocationGallery(ev.locationImages ?? []);

  const rsvpEnabled = !!ev?.rsvp?.enabled;
  const rsvpCta = ev?.rsvp?.ctaText ?? "Confirmar presença";
  const rsvpLink = buildWhatsappLink(ev?.rsvp?.whatsappPhoneE164, ev?.rsvp?.whatsappPrefill);
  const rsvpBtns = document.querySelectorAll<HTMLAnchorElement>("[data-rsvp-btn]");
  for (const rsvpBtn of rsvpBtns) {
    rsvpBtn.textContent = rsvpCta;
    if (rsvpEnabled && rsvpLink) {
      rsvpBtn.href = rsvpLink;
      rsvpBtn.hidden = false;
    } else {
      rsvpBtn.hidden = true;
    }
  }
  (globalThis as any).__stickyCta?.setAvailable?.(!!(rsvpEnabled && rsvpLink));

  setEnabled("about", !!sections?.about?.enabled);
  setText("about.title", sections?.about?.title);
  setText("about.text", sections?.about?.text);

  setEnabled("important", !!sections?.important?.enabled);
  setText("important.title", sections?.important?.title);
  renderBullets("[data-important]", sections?.important?.bullets ?? []);

  setEnabled("rules", !!sections?.rules?.enabled);
  setText("rules.title", sections?.rules?.title);
  renderBullets("[data-rules]", sections?.rules?.bullets ?? []);

  setEnabled("whatToBring", !!sections?.whatToBring?.enabled);
  setText("whatToBring.title", sections?.whatToBring?.title);
  renderBullets("[data-whatToBring]", sections?.whatToBring?.bullets ?? []);

  setEnabled("gallery", !!sections?.gallery?.enabled);
  setText("gallery.title", sections?.gallery?.title);
  renderGallery(sections?.gallery?.images ?? []);

  setEnabled("faq", !!sections?.faq?.enabled);
  setText("faq.title", sections?.faq?.title);
  renderFaq(sections?.faq?.items ?? []);

  for (const chip of document.querySelectorAll<HTMLElement>("[data-nav]")) {
    const id = chip.getAttribute("data-nav");
    const enabled = id ? !qs<HTMLElement>(`[data-section="${id}"]`)?.hidden : true;
    chip.hidden = !enabled;
  }
}

function setupMusic(musicCfg: Nullable<MusicConfig>) {
  const gate = qs<HTMLElement>("[data-gate]");
  const gateBtn = qs<HTMLButtonElement>("[data-gate-btn]");
  const audio = qs<HTMLAudioElement>("[data-audio]");
  const fab = qs<HTMLButtonElement>("[data-musicfab]");
  if (!audio || !fab) return;

  const enabled = !!musicCfg?.enabled;
  const src = String(musicCfg?.src ?? "").trim();
  const volume = clamp01(musicCfg?.volume ?? 0.85);
  const loop = musicCfg?.loop !== false;
  const startAtSecondsRaw = Number(musicCfg?.startAtSeconds ?? 0);
  const startAtSeconds = Number.isFinite(startAtSecondsRaw) ? Math.max(0, startAtSecondsRaw) : 0;

  setTextAll("music.hint", musicCfg?.hint ?? "Toque para iniciar a música");
  if (gateBtn) gateBtn.textContent = musicCfg?.startLabel ?? "Abrir convite";

  if (!enabled || !src) {
    if (gate) gate.hidden = true;
    fab.hidden = true;
    return;
  }

  audio.src = src;
  audio.loop = loop;
  audio.volume = typeof volume === "number" ? volume : 0.85;

  const setFab = (isPlaying: boolean) => {
    fab.textContent = isPlaying ? "⏸" : "▶";
    fab.setAttribute("aria-pressed", isPlaying ? "true" : "false");
    fab.setAttribute("aria-label", isPlaying ? "Pausar música" : "Tocar música");
  };

  const seekToStart = () => {
    if (!startAtSeconds) return;
    try {
      if (Number.isFinite(audio.duration) && audio.duration > 0) {
        audio.currentTime = Math.min(startAtSeconds, Math.max(0, audio.duration - 0.25));
      }
    } catch {
      // ignore
    }
  };

  const play = async () => {
    try {
      seekToStart();
      await audio.play();
      setFab(true);
    } catch {
      setFab(false);
    }
  };

  const pause = () => {
    audio.pause();
    setFab(false);
  };

  audio.addEventListener("loadedmetadata", seekToStart, { once: true });

  // Modo "gate" (página antiga): botão abre e inicia música.
  if (gate && gateBtn) {
    gateBtn.addEventListener("click", async () => {
      gate.hidden = true;
      fab.hidden = false;
      await play();
    });
  } else {
    // Modo "convite": inicia no primeiro gesto do usuário.
    fab.hidden = true;
    const unlock = async () => {
      fab.hidden = false;
      await play();
    };
    const onPointer = () => void unlock();
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Tab") return;
      void unlock();
    };
    window.addEventListener("pointerdown", onPointer, { once: true, passive: true });
    window.addEventListener("keydown", onKey, { once: true });
  }

  fab.addEventListener("click", async () => {
    if (audio.paused) await play();
    else pause();
  });

  audio.addEventListener("play", () => setFab(true));
  audio.addEventListener("pause", () => setFab(false));
}

function preloadAssets(cfg: AppConfig) {
  const isMobile = window.matchMedia("(max-width: 560px)").matches;
  const bg = cfg?.background ?? {};
  const sections = cfg?.sections ?? {};
  const ev = cfg?.event ?? {};

  const dedupe = (arr: string[]) => [...new Set(arr.filter(Boolean))];
  const isVideo = (src: string) => /\.(mp4|webm|mov)$/i.test(src);
  const isImage = (src: string) => /\.(png|jpe?g|webp|avif|gif)$/i.test(src);

  const backgroundMedia = Array.isArray(bg?.media) ? bg.media : [];
  const backgroundImages = Array.isArray(bg?.images) ? bg.images : [];
  const galleryImages = Array.isArray(sections?.gallery?.images) ? sections.gallery!.images! : [];
  const locationImages = Array.isArray(ev?.locationImages) ? ev.locationImages : [];

  // Ordem importa: prioriza o que aparece primeiro (fundo + local + galeria)
  const all = dedupe([...backgroundMedia, ...backgroundImages, ...locationImages, ...galleryImages]);
  const images = all.filter((s) => isImage(s));
  const videos = all.filter((s) => isVideo(s));

  // Preload de imagens: esquenta cache sem bloquear UI
  for (const src of images) {
    const img = new Image();
    img.decoding = "async";
    img.loading = "eager";
    img.src = src;
  }

  // Preload de vídeos: apenas metadata (não baixa o vídeo inteiro).
  // Em mobile isso também ajuda a reduzir o "primeiro play", sem pesar tanto.
  for (const src of videos) {
    const v = document.createElement("video");
    v.preload = "metadata";
    forceMutedInline(v);
    v.src = src;
    try {
      v.load();
    } catch {
      // ignore
    }
  }
}

function showError(err: unknown) {
  const box = qs<HTMLElement>("[data-error]");
  if (!box) return;
  box.hidden = false;
  box.textContent = `Erro: ${err instanceof Error ? err.message : String(err)}`;
}

document.addEventListener("DOMContentLoaded", async () => {
  try {
    const syncViewportVars = () => setVisualVhCssVar();
    const syncViewportVarsRaf = () => requestAnimationFrame(syncViewportVars);

    // Primeiro paint + 1 tick depois (Safari às vezes ajusta viewport após layout)
    syncViewportVars();
    setTimeout(syncViewportVars, 60);

    window.addEventListener("resize", syncViewportVarsRaf, { passive: true });
    window.addEventListener("orientationchange", syncViewportVarsRaf, { passive: true });
    window.addEventListener("scroll", syncViewportVarsRaf, { passive: true });

    // iOS Safari: visualViewport muda com barra do navegador/zoom/scroll
    window.visualViewport?.addEventListener("resize", syncViewportVarsRaf, { passive: true });
    window.visualViewport?.addEventListener("scroll", syncViewportVarsRaf, { passive: true });

    setupActiveNav();
    (globalThis as any).__stickyCta = setupStickyCta();

    const onVis = () => {
      document.documentElement.style.setProperty("--mosaic-play", document.hidden ? "paused" : "running");
    };
    document.addEventListener("visibilitychange", onVis, { passive: true } as any);
    onVis();

    const cfg = await loadConfig();
    applyConfig(cfg);
    setupMusic(cfg?.music);
    // Já na tela do "Abrir convite", começa a esquentar as mídias da próxima tela.
    const start = () => preloadAssets(cfg);
    if ("requestIdleCallback" in window) (window as any).requestIdleCallback(start, { timeout: 1200 });
    else globalThis.setTimeout(start, 250);
    document.title = cfg?.event?.title ? `${cfg.event.title}` : "Convite";
  } catch (e) {
    console.error(e);
    showError(e);
  }
});

